/**
 * Calculates (base^exp) % mod efficiently.
 * @param {bigint} base 
 * @param {bigint} exp 
 * @param {bigint} mod 
 * @returns {bigint}
 */
function power(base, exp, mod) {
    let res = 1n;
    base %= mod;
    while (exp > 0n) {
        if (exp % 2n === 1n) {
            res = (res * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2n;
    }
    return res;
}

/**
 * Calculates modular inverse using Fermat's Little Theorem: a^(M-2) % M.
 * M must be prime.
 * @param {bigint} n 
 * @param {bigint} mod 
 * @returns {bigint}
 */
function modInverse(n, mod) {
    return power(n, mod - 2n, mod);
}

/**
 * Solves the visibility counting problem.
 * @param {number} n Total number of people.
 * @param {number} pos Position of the observer.
 * @param {number} k Target number of visible people.
 * @returns {number} The count modulo 10^9 + 7.
 */
function solve(n, pos, k) {
    const MOD = 1000000007n;

    if (k < 0 || k > n - 1) {
        return 0;
    }

    if (n === 1) {
        // If n=1, pos=0. k must be 0. Result is 2 (L or R).
        return 2;
    }

    // We need to calculate C(N-1, K) mod MOD.
    const N_minus_1 = n - 1;
    const K_num = k;

    // Precompute factorials up to N-1
    const MAX_FACT = N_minus_1;
    const fact = new Array(MAX_FACT + 1);
    fact[0] = 1n;
    for (let i = 1; i <= MAX_FACT; i++) {
        fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    }

    /**
     * Calculates nCk mod MOD.
     * @param {number} n 
     * @param {number} k 
     * @returns {bigint} C(n, k) mod MOD
     */
    const combinations = (n, k) => {
        if (k < 0 || k > n) {
            return 0n;
        }
        if (k === 0 || k === n) {
            return 1n;
        }
        if (k > n / 2) {
            k = n - k;
        }

        // C(n, k) = n! / (k! * (n-k)!)
        const numerator = fact[n];
        const denominator = (fact[k] * fact[n - k]) % MOD;

        return (numerator * modInverse(denominator, MOD)) % MOD;
    };

    // Calculate C(N-1, K)
    const C_NK = combinations(N_minus_1, K_num);

    // The observer at 'pos' has 2 independent choices ('L' or 'R').
    // Total ways = C(N-1, K) * 2
    let result = (C_NK * 2n) % MOD;

    return Number(result);
}

